// test/problems.components.meta.spec.js
const { expect } = require('chai');
const ProblemsService = require('../../modules/Problems/services/ProblemsService');

describe('ProblemsService component metadata aggregation', () => {
  // Sample problems data for testing
  const problems = [
    {
      id: 1,
      components: [
        { language: 'Java', status: 'passed', difficulty: 2, tags: ['dp'] },
        { language: 'Python', status: 'failed', difficulty: 2, tags: ['dp'] },
      ],
    },
    {
      id: 2,
      components: [
        { language: 'Java', status: 'passed', difficulty: 3, tags: ['graphs'] },
        { language: 'C++', status: 'failed', difficulty: 3, tags: ['graphs'] },
      ],
    },
    {
      id: 3,
      components: [
        { language: 'Python', status: 'passed', difficulty: 1, tags: ['dp', 'graphs'] },
      ],
    },
  ];

  it('should aggregate componentLanguageTotals and componentStatusTotals with filters and limits', () => {
    const service = new ProblemsService(problems);

    // Filter: difficulty <= 2, tag 'dp', limit 2
    const result = service.getComponentMetadata({
      includeComponents: true,
      difficulty: 2,
      tags: ['dp'],
      limit: 2,
    });

    expect(result.componentLanguageTotals).to.deep.equal({
      Java: 1,
      Python: 2,
    });

    expect(result.componentStatusTotals).to.deep.equal({
      passed: 2,
      failed: 1,
    });
  });
});
